  box-shadow: var(--shadow-card);
  grid-template-columns: minmax(180px, 220px) 1px 1fr;
  gap: 28px;
}

.leftover-card__amount {
  @apply flex flex-col items-center justify-center text-center;
}

.leftover-card__figure {
  @apply font-semibold text-brand;
  font-size: 56px;
  line-height: 1;
  letter-spacing: -1px;
  margin-bottom: 10px;
}

.leftover-card__caption {
  @apply text-ink-muted;
  font-size: 14px;
}

.leftover-card__divider {
  @apply bg-line;
  width: 1px;
  height: 100%;
}

.leftover-card__body {
  @apply flex flex-col items-start;
  gap: 12px;
}

.leftover-card__badge {
  @apply inline-flex items-center gap-2 text-sm font-medium;
  padding: 5px 12px;
  border-radius: var(--radius-pill);
  border: 1px solid transparent;
}

.leftover-card__badge--warning {
  @apply text-brand;
  background: var(--color-brand-soft);
  border-color: var(--color-brand-line);
}

.leftover-card__badge--success {
  @apply text-success;
  background: var(--color-success-soft);
}

.leftover-card__badge--danger {
  @apply text-danger;
  background: var(--color-danger-soft);
}

