import { formatSignedCurrency, formatCurrency } from '../../lib/format'
import type { IncomeItem } from '../../data/mockFinances'
import './MonthlyMoneyCard.css'

type Props = {
  income: IncomeItem[]
}

export function MonthlyMoneyCard({ income }: Props) {
  const total = income.reduce((sum, item) => sum + item.amount, 0)

  return (
    <article className="money-card">
      <h3 className="money-card__eyebrow">Your money this month</h3>
      <span className="money-card__pill">Income</span>
      <ul className="money-card__rows">
        {income.map((item) => (
          <li className="money-card__row" key={item.label}>
            <span className="money-card__row-label">{item.label}</span>
            <span className="money-card__row-amount">{formatSignedCurrency(item.amount)}</span>
          </li>
        ))}
        <li className="money-card__row money-card__row--total">
          <span className="money-card__row-label">Total income</span>
          <span className="money-card__row-amount">{formatCurrency(total)}</span>
        </li>
      </ul>
    </article>
  )
}

