import './SupportCard.css'

type Props = {
  intro: string
  links: SupportLink[]
}

export function SupportCard({ intro, links }: Props) {
  return (
    <article className="support-card">
      <h3 className="support-card__title">Free support is available</h3>
      <p className="support-card__intro">{intro}</p>
      <ul className="support-card__links">
        {links.map((link) => (
          <li key={link.href}>
            <a className="support-card__link" href={link.href} target="_blank" rel="noreferrer">
              <span>{link.label}</span>
              <span className="support-card__icon" aria-hidden="true" />
            </a>
          </li>
        ))}
      </ul>
    </article>
  )
}

.support-card {
  @apply border border-line;
  background: var(--color-surface-muted);
  padding: 22px 24px;
  border-radius: var(--radius-card);
}

.support-card__title {
  @apply text-ink font-semibold;
  font-size: 15px;
  margin-bottom: 10px;
}

.support-card__intro {
  @apply text-ink-muted;
  font-size: 13px;
  line-height: 1.55;
  margin-bottom: 18px;
}

.support-card__links {
  @apply list-none p-0 m-0;
}

.support-card__links li {
  border-top: 1px solid var(--color-line-strong);
}

.support-card__link {
  @apply flex items-center justify-between text-accent no-underline;
  padding: 12px 0;
  font-size: 14px;
}

.support-card__link:hover {
  @apply underline;
}

.support-card__icon {
  width: 12px;
  height: 12px;
  border: 1.5px solid var(--color-accent);
  border-radius: 2px;
  display: inline-block;
}

